"use client";

import { useState } from "react";
import { FormProvider, useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useResendVerification } from "@/lib/api/hooks/auth/auth.hooks";
import FormFieldComp from "@/components/formfield";
import Link from "next/link";
import { useRouter } from "next/navigation";

interface VerificationFailedClientProps {
  reason?: string;
}

const formSchema = z.object({
  email: z.string().email("Please enter a valid email address"),
});

type FormValues = z.infer<typeof formSchema>;

const getFailureContent = (reason?: string) => {
  switch (reason) {
    case "expired":
      return {
        title: "Verification link expired",
        description:
          "Your email verification link has expired. Enter your email below to receive a new verification link.",
      };
    case "invalid":
      return {
        title: "Invalid verification link",
        description:
          "This verification link is invalid or has been tampered with. Enter your email below to receive a fresh verification link.",
      };
    default:
      return {
        title: "Email verification failed",
        description:
          "We could not verify your email address. Enter your email below to request a new verification email.",
      };
  }
};

export default function VerificationFailedClient({ reason }: VerificationFailedClientProps) {
  const { title, description } = getFailureContent(reason);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const { mutate, isPending } = useResendVerification();
  const router = useRouter()

  const form = useForm<FormValues>({
    resolver: zodResolver(formSchema),
  });

  const onSubmit = (data: FormValues) => {
    mutate(data, {
      onSuccess: (data) => {
        if(data.message.includes("Email is already verified.")){
          router.replace("/login")
        }
      }
    });
    setIsSubmitted(true);
  };

  if (isSubmitted) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50 px-4 py-10">
        <div className="w-full max-w-lg rounded-3xl border border-slate-200 bg-white p-10 text-center shadow-sm">
          <h1 className="text-2xl font-semibold text-slate-900">Check your email</h1>
          <p className="mt-4 text-sm leading-6 text-slate-600">
            We've sent a new verification link to your email address. Please check your inbox and click the link to verify your account.
          </p>
          <div className="mt-8">
            <Button onClick={() => setIsSubmitted(false)} variant="outline" className="mr-4">
              Try another email
            </Button>
            <Button asChild>
              <a href="/login">Go to Login</a>
            </Button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 px-4 py-10">
      <div className="w-full max-w-lg rounded-3xl border border-slate-200 bg-white p-10 text-center shadow-sm">
        <h1 className="text-2xl font-semibold text-slate-900">{title}</h1>
        <p className="mt-4 text-sm leading-6 text-slate-600">{description}</p>

        <FormProvider {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="mt-8 space-y-4">
            <FormFieldComp
              name="email"
              control={form.control}
              type="email"
              placeholder="Enter email address"
              label="Email Address"
              autoComplete="one-time-code"
            />

            <Button
              type="submit"
              variant={"regular"}
              disabled={form.formState.isSubmitting || isPending}
              className="w-full"
            >
              Resend verification email
            </Button>
          </form>
        </FormProvider>
      </div>
    </div>
  );
}

"use client";

import { Suspense } from "react";
import { useEffect, useRef } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { Spinner } from "@/components/spinner";
import { showErrorToast, showSuccessToast } from "@/lib/toast-helpers";
import { useQuery } from "@tanstack/react-query";
import { verifyEmail } from "@/lib/api/services/auth/auth.services";
import { useAuthStore } from "@/store/use-auth-store";

function VerifyEmailContent() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const token = searchParams.get("token") ?? "";
  const { data, isLoading, isError, isSuccess, error } = useQuery({
    queryKey: ["auth", "user"],
    queryFn: () => verifyEmail(token),
    retry: false,
    enabled: !!token,
  });
  const setUserEmailVerified = useAuthStore(
    (state) => state.setUserEmailVerified,
  );
  const user = useAuthStore((state) => state.user);
  const role = user?.role;

  const hasCalledRef = useRef(false);

  useEffect(() => {
    if (!token) {
      router.replace("/verification-failed?reason=invalid");
      return;
    }

    if (hasCalledRef.current || (!isSuccess && !isError)) {
      return;
    }

    hasCalledRef.current = true;

    if (isSuccess && data) {
      showSuccessToast(data.message);
      setUserEmailVerified(true);

      // Wait for 2 seconds to allow the user to read the success message
      setTimeout(() => {
        if (role === "ADMIN") {
          router.replace("/admin");
        } else if (role === "USER") {
          router.replace("/user");
        } else {
          // No role in store yet (e.g. user landed on link without being logged in)
          router.replace("/login");
        }
      }, 2000);
    }

    if (isError) {
      const rawMessage = error?.message ?? "Verification failed.";
      const lowerMessage = String(rawMessage).toLowerCase();

      if (
        lowerMessage.includes("already verified") ||
        lowerMessage.includes("already been verified")
      ) {
        showSuccessToast(rawMessage);
        setUserEmailVerified(true);

        setTimeout(() => {
          router.replace("/login");
        }, 2000);
        return;
      }

      showErrorToast(rawMessage);

      if (lowerMessage.includes("expired")) {
        setTimeout(() => {
          router.replace("/verification-failed?reason=expired");
        }, 2000);
        return;
      }

      setTimeout(() => {
        router.replace("/verification-failed?reason=invalid");
      }, 2000);
    }
  }, [router, token, isSuccess, data, isError, error, setUserEmailVerified, role]);

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 px-4 py-10">
      <div className="w-full max-w-lg rounded-3xl border border-slate-200 bg-white p-10 text-center shadow-sm">
        <div className="mx-auto mb-6 flex h-20 w-20 items-center justify-center rounded-full bg-slate-100">
          <Spinner className="h-10 w-10 text-primary" size={40} />
        </div>
        <h1 className="text-xl font-semibold text-slate-900">
          Verifying your email address...
        </h1>
        <p className="mt-3 text-sm text-slate-600">
          Please wait while we confirm your account and redirect you to the
          right dashboard.
        </p>
      </div>
    </div>
  );
}

export default function VerifyEmailPage() {
  return (
    <Suspense
      fallback={
        <div className="min-h-screen flex items-center justify-center bg-slate-50">
          <Spinner size={40} />
        </div>
      }
    >
      <VerifyEmailContent />
    </Suspense>
  );
}

