"use client";

import { useState, useEffect } from "react";
import { useWatch } from "react-hook-form";
import { AddBlogFormValues } from "@/schemas/add-blog-schema";
import Image from "next/image";

export default function BlogPreview() {
  const values = useWatch<AddBlogFormValues>();
  const { title, author, excerpt, coverImage, content } =
    values as AddBlogFormValues;
  const [coverSrc, setCoverSrc] = useState<string | null>(null);

  // Resolve cover image src safely without memory leaks
  useEffect(() => {
    if (coverImage instanceof File) {
      const objectUrl = URL.createObjectURL(coverImage);
      setCoverSrc(objectUrl);
      return () => URL.revokeObjectURL(objectUrl);
    } else if (typeof coverImage === "string" && coverImage.length > 0) {
      setCoverSrc(coverImage);
    } else {
      setCoverSrc(null);
    }
  }, [coverImage]);

  return (
    <article className="max-w-3xl mx-auto space-y-8 py-6">
      <header className="space-y-4">
        <h1 className="text-3xl font-bold leading-tight text-foreground">
          {title || (
            <span className="text-muted-foreground">Untitled Post</span>
          )}
        </h1>

        {author && (
          <p className="text-sm text-muted-foreground">
            By <span className="font-medium text-foreground">{author}</span>
          </p>
        )}

        {excerpt && (
          <p className="text-base text-muted-foreground leading-relaxed border-l-4 border-border pl-4 italic">
            {excerpt}
          </p>
        )}

        {coverSrc && (
          <div className="relative w-full aspect-video rounded-xl overflow-hidden border border-border">
            <Image
              src={coverSrc}
              alt={title || "Cover image"}
              fill
              className="object-cover"
              unoptimized={coverImage instanceof File}
            />
          </div>
        )}
      </header>

      <div
        className="prose prose-sm max-w-none"
        dangerouslySetInnerHTML={{
          __html:
            content ||
            "<p class='text-muted-foreground'>Nothing written yet…</p>",
        }}
      />
    </article>
  );
}

"use client";

import { useEditor, EditorContent } from "@tiptap/react";
import StarterKit from "@tiptap/starter-kit";
import Placeholder from "@tiptap/extension-placeholder";
import Link from "@tiptap/extension-link";
import Typography from "@tiptap/extension-typography";
import TextAlign from "@tiptap/extension-text-align";
import UnderlineExt from "@tiptap/extension-underline";
import Highlight from "@tiptap/extension-highlight";
import { useEffect } from "react";
import {
  AlignCenter,
  AlignLeft,
  AlignRight,
  Bold,
  Heading1,
  Heading2,
  Heading3,
  Highlighter,
  Italic,
  List,
  ListOrdered,
  Strikethrough,
  Underline,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { Toggle } from "@/components/ui/toggle";

interface TiptapEditorProps {
  value: string;
  onChange: (html: string) => void;
}

export default function TiptapEditor({ value, onChange }: TiptapEditorProps) {
  const editor = useEditor({
    extensions: [
      StarterKit,
      Placeholder.configure({ placeholder: "Write your blog content here…" }),
      Link.configure({ openOnClick: false }),
      Typography,
      UnderlineExt,
      Highlight,
      TextAlign.configure({ types: ["heading", "paragraph"] }),
    ],
    immediatelyRender: false,
    content: value || "",
    onUpdate({ editor }) {
      onChange(editor.getHTML());
    },
    editorProps: {
      attributes: {
        class: "prose prose-sm max-w-none min-h-[400px] p-4 focus:outline-none",
      },
    },
  });

  const Options =
    editor === null
      ? []
      : [
          {
            icon: <Bold />,
            onClick: () => editor.chain().focus().toggleBold().run(),
            pressed: editor.isActive("bold"),
          },
          {
            icon: <Italic />,
            onClick: () => editor.chain().focus().toggleItalic().run(),
            pressed: editor.isActive("italic"),
          },
          {
            icon: <Underline />,
            onClick: () => editor.chain().focus().toggleUnderline().run(),
            pressed: editor.isActive("underline"),
          },
          { separator: true },
          {
            icon: <Heading1 />,
            onClick: () =>
              editor.chain().focus().toggleHeading({ level: 1 }).run(),
            pressed: editor.isActive("heading", { level: 1 }),
          },
          {
            icon: <Heading2 />,
            onClick: () =>
              editor.chain().focus().toggleHeading({ level: 2 }).run(),
            pressed: editor.isActive("heading", { level: 2 }),
          },
          {
            icon: <Heading3 />,
            onClick: () =>
              editor.chain().focus().toggleHeading({ level: 3 }).run(),
            pressed: editor.isActive("heading", { level: 3 }),
          },
          { separator: true },
          {
            icon: <AlignLeft />,
            onClick: () => editor.chain().focus().setTextAlign("left").run(),
            pressed: editor.isActive({ textAlign: "left" }),
          },
          {
            icon: <AlignCenter />,
            onClick: () => editor.chain().focus().setTextAlign("center").run(),
            pressed: editor.isActive({ textAlign: "center" }),
          },
          {
            icon: <AlignRight />,
            onClick: () => editor.chain().focus().setTextAlign("right").run(),
            pressed: editor.isActive({ textAlign: "right" }),
          },
          { separator: true },
          {
            icon: <List />,
            onClick: () => editor.chain().focus().toggleBulletList().run(),
            pressed: editor.isActive("bulletList"),
          },
          {
            icon: <ListOrdered />,
            onClick: () => editor.chain().focus().toggleOrderedList().run(),
            pressed: editor.isActive("orderedList"),
          },
          { separator: true },
          {
            icon: <Strikethrough />,
            onClick: () => editor.chain().focus().toggleStrike().run(),
            pressed: editor.isActive("strike"),
          },
          {
            icon: <Highlighter />,
            onClick: () => editor.chain().focus().toggleHighlight().run(),
            pressed: editor.isActive("highlight"),
          },
        ];

  useEffect(() => {
    if (!editor) return;
    const currentHTML = editor.getHTML();
    if (currentHTML !== value) {
      editor.commands.setContent(value || "");
    }
  }, [value]);

  return (
    <div className="border border-input rounded-lg overflow-hidden">
      {/* Toolbar */}
      <div className="flex flex-wrap items-center gap-0.5 border-b border-input bg-muted/40 px-2 py-1.5">
        {Options.map((option, i) =>
          "separator" in option ? (
            <div key={i} className="w-px h-5 bg-border mx-1" />
          ) : (
            <Toggle
              key={i}
              size="sm"
              pressed={option.pressed}
              onPressedChange={option.onClick}
              aria-label="Toggle tool"
              className="data-[state=on]:bg-brand-green data-[state=on]:text-white hover:bg-muted"
            >
              {option.icon}
            </Toggle>
          ),
        )}
      </div>

      {/* Editor area */}
      <EditorContent editor={editor} className="cursor-text" />
    </div>
  );
}

