            alt="Login background"
            fill
            className="object-cover"
            priority
          />
        </div>
      </div>

      {/* Right side Form */}
      <div className="w-full lg:w-1/2 md:p-5 sm:p-8 lg:p-12 flex flex-col gap-8 md:gap-8 justify-center ">
