// get the currently logged in user and set it in the auth store. This is used to persist the user session across page reloads and to check the user's authentication status when the app loads. If the user is not authenticated, we clear the user from the auth store.
export const useGetCurrentUser = () => {
  const setUser = useAuthStore((state) => state.setUser);
  const clearUser = useAuthStore((state) => state.clearUser);

  const query = useQuery({
    queryKey: ["auth", "user"],
    queryFn: getCurrentUser,
    retry: false,
  });

  useEffect(() => {
    if (query.isSuccess && query.data?.data) {
      setUser(query.data?.data, "email");
    } else if (query.isError) {
      clearUser();
    }
  }, [query.isSuccess, query.isError, query.data, setUser, clearUser]);

  return query;
};

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import {
  getCamps,
  getCamp,
  createCamp,
  updateCamp,
  deleteCamp,
  CreateCampPayload,
  UpdateCampPayload,
} from "../../services/camps/camps.services";
import { showSuccessToast, showErrorToast } from "@/lib/toast-helpers";

export const useGetCamps = () => {
  return useQuery({
    queryKey: ["camps"],
    queryFn: getCamps,
    retry: false,
  });
};

export const useGetCamp = (campId: string) => {
  return useQuery({
    queryKey: ["camps", campId],
    queryFn: () => getCamp(campId),
    enabled: Boolean(campId),
    retry: false,
  });
};

export const useCreateCamp = () => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: createCamp,
    onSuccess: (data) => {
      showSuccessToast(data.message);
      queryClient.invalidateQueries({ queryKey: ["camps"] });
    },
    onError: (error: any) => {
      showErrorToast(error.message);
    },
  });
};

export const useUpdateCamp = () => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: ({ id, payload }: { id: string; payload: UpdateCampPayload }) =>
      updateCamp(id, payload),
    onSuccess: (data) => {
      showSuccessToast(data.message);
      queryClient.invalidateQueries({ queryKey: ["camps"] });
    },
    onError: (error: any) => {
      showErrorToast(error.message);
    },
  });
};

export const useDeleteCamp = () => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: deleteCamp,
    onSuccess: (data) => {
      showSuccessToast(data.message);
      queryClient.invalidateQueries({ queryKey: ["camps"] });
